#!/usr/bin/env python3
"""Build machine-readable postmortem summary from existing analysis artifacts."""

from __future__ import annotations

import json
import re
import sys
from datetime import date
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
TIMELINE_PATH = ROOT / "analysis" / "incident_timeline.md"
ROOT_CAUSE_PATH = ROOT / "analysis" / "root_cause_analysis.md"
ALERT_PATH = ROOT / "analysis" / "alert_silence_analysis.md"
PR_REVIEW_PATH = ROOT / "analysis" / "pr_review_analysis.md"
CI_GAP_PATH = ROOT / "docs" / "ci_test_gap_analysis.md"
PROD_LOG_PATH = ROOT / "production-error-log.md"


def fail(message: str) -> None:
    print(json.dumps({"error": message}, ensure_ascii=False), file=sys.stderr)
    raise SystemExit(1)


def read(path: Path) -> str:
    return path.read_text(encoding="utf-8") if path.exists() else ""


def parse_date(label: str, text: str) -> date:
    match = re.search(rf"\|\s*{re.escape(label)}\s*\|\s*`?(\d{{4}}-\d{{2}}-\d{{2}})`?\s*\|", text)
    if not match:
        fail(f"{label} not found")
    return date.fromisoformat(match.group(1))


def parse_offset_minutes(*texts: str) -> int:
    merged = "\n".join(texts)
    match = re.search(r"offset_minutes\s*\|\s*`?(\d+)`?", merged)
    if match:
        return int(match.group(1))
    match = re.search(r"delta=\+?(\d+)min", merged)
    if match:
        return int(match.group(1))
    fail("offset minutes not found")


def main() -> None:
    timeline = read(TIMELINE_PATH)
    root_cause = read(ROOT_CAUSE_PATH)
    alert = read(ALERT_PATH)
    pr_review = read(PR_REVIEW_PATH)
    ci_gap = read(CI_GAP_PATH)
    prod = read(PROD_LOG_PATH)

    dst_switch = parse_date("dst_switch", timeline)
    violation_date = parse_date("violation_date", timeline)

    contributing_factors: list[str] = []
    if "mock 日期" in ci_gap or "CI" in root_cause:
        contributing_factors.append("ci_dst_coverage_gap")
    if "rule_007" in alert and "expires: null" in alert:
        contributing_factors.append("alert_silence_no_expiry")
    if "未识别 DST 风险" in pr_review or "knowledge gap" in pr_review or "知识盲点" in pr_review:
        contributing_factors.append("review_missed_dst_risk")
    if len(contributing_factors) < 3:
        fail("fewer than three contributing factors detected")

    result = {
        "root_cause": "dst_fixed_offset_naive_datetime",
        "contributing_factors": contributing_factors,
        "timeline_days_from_dst_switch_to_violation": (violation_date - dst_switch).days,
        "offset_minutes": parse_offset_minutes(timeline, root_cause, prod),
        "prevention_measures": [
            "Use timezone-aware datetime with zoneinfo.ZoneInfo('Asia/Shanghai') instead of fixed +8 offsets.",
            "Add DST boundary and midday cutoff tests to CI and remove non-expiring TZ_CONVERT alert silences.",
        ],
    }
    print(json.dumps(result, ensure_ascii=False, separators=(",", ":")))


if __name__ == "__main__":
    main()

